
"use client"

import { useState, useEffect } from "react";
import { BottomNav } from "@/components/layout/bottom-nav";
import { Button } from "@/components/ui/button";
import { Card } from "@/components/ui/card";
import { Badge } from "@/components/ui/badge";
import { Avatar, AvatarFallback, AvatarImage } from "@/components/ui/avatar";
import { Settings, Share2, Zap, MapPin, Loader2, Edit3, Check, UserCircle } from "lucide-react";
import { Dialog, DialogContent, DialogHeader, DialogTitle, DialogTrigger, DialogFooter } from "@/components/ui/dialog";
import { Input } from "@/components/ui/input";
import { Label } from "@/components/ui/label";
import { Textarea } from "@/components/ui/textarea";
import { Select, SelectContent, SelectItem, SelectTrigger, SelectValue } from "@/components/ui/select";
import Image from "next/image";
import { useUser, useDoc, useFirestore, useMemoFirebase, updateDocumentNonBlocking } from "@/firebase";
import { doc } from "firebase/firestore";
import { useToast } from "@/hooks/use-toast";
import { cn } from "@/lib/utils";

const AVATAR_OPTIONS = [
  { id: 'anime-car-1', url: 'https://picsum.photos/seed/gtr-anime/200/200', label: 'GTR Anime' },
  { id: 'anime-car-2', url: 'https://picsum.photos/seed/supra-anime/200/200', label: 'Supra Anime' },
  { id: 'anime-car-3', url: 'https://picsum.photos/seed/m3-anime/200/200', label: 'M3 Anime' },
  { id: 'anime-car-4', url: 'https://picsum.photos/seed/rx7-anime/200/200', label: 'RX7 Anime' },
  { id: 'anime-car-5', url: 'https://picsum.photos/seed/911-anime/200/200', label: '911 Anime' },
  { id: 'anime-car-6', url: 'https://picsum.photos/seed/lancer-anime/200/200', label: 'Evo Anime' },
];

const KOSOVO_CITIES = [
  "Prishtinë", "Prizren", "Pejë", "Gjakovë", "Mitrovicë", "Gjilan", "Ferizaj", 
  "Vushtrri", "Podujevë", "Rahovec", "Fushë Kosovë", "Suharekë", "Kaçanik", 
  "Skënderaj", "Lipjan", "Malishevë", "Drenas", "Deçan", "Klinë", "Kamenicë", 
  "Dragash", "Istog", "Viti", "Obiliq", "Leposaviq", "Graçanicë", "Hani i Elezit", 
  "Zveçan", "Shtime", "Novobërdë", "Zubin Potok", "Junik", "Mamushë", 
  "Ranillug", "Partesh", "Kllokot"
];

export default function ProfilePage() {
  const { user, isUserLoading } = useUser();
  const db = useFirestore();
  const { toast } = useToast();
  const [isEditDialogOpen, setIsEditDialogOpen] = useState(false);

  const [formData, setFormData] = useState({
    username: "",
    city: "",
    carBrand: "",
    carModel: "",
    horsepower: 0,
    modifications: "",
    profilePhotoUrl: "",
  });

  const profileRef = useMemoFirebase(() => {
    if (!user || !db) return null;
    return doc(db, "users", user.uid);
  }, [user, db]);

  const { data: profile, isLoading: isProfileLoading } = useDoc(profileRef);

  useEffect(() => {
    if (profile) {
      setFormData({
        username: profile.username || "",
        city: profile.city || "Prishtinë",
        carBrand: profile.carBrand || "",
        carModel: profile.carModel || "",
        horsepower: profile.horsepower || 0,
        modifications: profile.modifications || "",
        profilePhotoUrl: profile.profilePhotoUrl || AVATAR_OPTIONS[0].url,
      });
    }
  }, [profile]);

  const handleSaveProfile = () => {
    if (!profileRef) return;

    const updatedData = {
      ...formData,
      horsepower: Number(formData.horsepower),
      updatedAt: new Date().toISOString(),
    };

    updateDocumentNonBlocking(profileRef, updatedData);
    
    toast({
      title: "Profili u përditësua",
      description: "Të dhënat tuaja u ruajtën me sukses.",
    });
    
    setIsEditDialogOpen(false);
  };

  if (isUserLoading || isProfileLoading) {
    return (
      <div className="flex flex-col min-h-screen bg-background items-center justify-center">
        <Loader2 className="w-10 h-10 text-accent animate-spin" />
      </div>
    );
  }

  return (
    <div className="flex flex-col min-h-screen bg-background text-foreground pb-24 overflow-x-hidden">
      <div className="p-6 flex justify-between items-center z-20">
        <div className="flex items-center gap-2">
          <UserCircle className="w-6 h-6 text-accent" />
          <h1 className="text-xl font-black italic uppercase tracking-tighter">PROFILI IM</h1>
        </div>
        <div className="flex gap-2">
          <Button size="icon" variant="outline" className="rounded-xl glass border-white/10 w-10 h-10"><Share2 className="w-4 h-4" /></Button>
          <Dialog open={isEditDialogOpen} onOpenChange={setIsEditDialogOpen}>
            <DialogTrigger asChild>
              <Button size="icon" variant="outline" className="rounded-xl glass border-white/10 w-10 h-10">
                <Settings className="w-4 h-4" />
              </Button>
            </DialogTrigger>
            <DialogContent className="glass border-white/10 text-foreground sm:max-w-[425px] max-h-[90vh] overflow-y-auto no-scrollbar">
              <DialogHeader>
                <DialogTitle className="text-xl font-black italic uppercase tracking-tighter">Ndrysho Profilin</DialogTitle>
              </DialogHeader>
              <div className="grid gap-6 py-4">
                <div className="grid gap-2">
                  <Label htmlFor="username" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Emri i Përdoruesit</Label>
                  <Input 
                    id="username" 
                    value={formData.username} 
                    onChange={(e) => setFormData({...formData, username: e.target.value})}
                    className="bg-white/5 border-white/10 rounded-xl"
                  />
                </div>
                
                <div className="grid gap-3">
                  <Label className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Zgjidh Ikonën (Stil Anime)</Label>
                  <div className="grid grid-cols-3 gap-3">
                    {AVATAR_OPTIONS.map((avatar) => (
                      <button
                        key={avatar.id}
                        onClick={() => setFormData({...formData, profilePhotoUrl: avatar.url})}
                        className={cn(
                          "relative aspect-square rounded-2xl overflow-hidden border-2 transition-all",
                          formData.profilePhotoUrl === avatar.url 
                            ? "border-accent ring-2 ring-accent/20 scale-95" 
                            : "border-white/5 opacity-60 hover:opacity-100"
                        )}
                      >
                        <Image src={avatar.url} alt={avatar.label} fill className="object-cover" />
                        {formData.profilePhotoUrl === avatar.url && (
                          <div className="absolute inset-0 bg-accent/20 flex items-center justify-center">
                            <Check className="text-white w-6 h-6 drop-shadow-md" />
                          </div>
                        )}
                        <div className="absolute bottom-0 left-0 right-0 bg-black/60 py-0.5">
                           <span className="text-[7px] font-black uppercase text-white block text-center">{avatar.label}</span>
                        </div>
                      </button>
                    ))}
                  </div>
                </div>

                <div className="grid gap-2">
                  <Label htmlFor="city" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Qyteti i Kosovës</Label>
                  <Select 
                    value={formData.city} 
                    onValueChange={(value) => setFormData({...formData, city: value})}
                  >
                    <SelectTrigger className="bg-white/5 border-white/10 rounded-xl h-12">
                      <SelectValue placeholder="Zgjidh qytetin" />
                    </SelectTrigger>
                    <SelectContent className="glass border-white/10 max-h-[300px]">
                      {KOSOVO_CITIES.map((city) => (
                        <SelectItem key={city} value={city} className="font-bold text-xs uppercase italic">
                          {city}
                        </SelectItem>
                      ))}
                    </SelectContent>
                  </Select>
                </div>
                
                <div className="grid gap-4">
                  <div className="grid gap-2">
                    <Label htmlFor="carBrand" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Marka e Mjetit</Label>
                    <Input 
                      id="carBrand"
                      placeholder="p.sh. BMW, Audi..."
                      value={formData.carBrand} 
                      onChange={(e) => setFormData({...formData, carBrand: e.target.value})}
                      className="bg-white/5 border-white/10 rounded-xl"
                    />
                  </div>

                  <div className="grid gap-2">
                    <Label htmlFor="carModel" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Modeli i Mjetit</Label>
                    <Input 
                      id="carModel"
                      placeholder="p.sh. M4, RS6..."
                      value={formData.carModel} 
                      onChange={(e) => setFormData({...formData, carModel: e.target.value})}
                      className="bg-white/5 border-white/10 rounded-xl"
                    />
                  </div>
                </div>

                <div className="grid gap-2">
                  <Label htmlFor="horsepower" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Fuqia (HP)</Label>
                  <Input 
                    id="horsepower" 
                    type="number"
                    value={formData.horsepower} 
                    onChange={(e) => setFormData({...formData, horsepower: parseInt(e.target.value) || 0})}
                    className="bg-white/5 border-white/10 rounded-xl"
                  />
                </div>
                <div className="grid gap-2">
                  <Label htmlFor="modifications" className="text-[10px] font-bold uppercase tracking-widest text-muted-foreground">Modifikimet</Label>
                  <Textarea 
                    id="modifications" 
                    placeholder="Stage 1, Downpipe, Akrapovic..."
                    value={formData.modifications} 
                    onChange={(e) => setFormData({...formData, modifications: e.target.value})}
                    className="bg-white/5 border-white/10 rounded-xl min-h-[80px]"
                  />
                </div>
              </div>
              <DialogFooter className="pt-4">
                <Button onClick={handleSaveProfile} className="w-full bg-accent text-background font-black italic uppercase rounded-xl h-12 shadow-xl neon-glow">
                  Ruaj Ndryshimet
                </Button>
              </DialogFooter>
            </DialogContent>
          </Dialog>
        </div>
      </div>

      <div className="px-6 py-4 relative z-10 flex flex-col items-center text-center">
        <Avatar className="w-40 h-40 rounded-[2.5rem] border-4 border-white/5 shadow-2xl overflow-hidden mb-6 bg-card">
          <AvatarImage src={profile?.profilePhotoUrl || AVATAR_OPTIONS[0].url} />
          <AvatarFallback className="text-4xl font-black italic">{profile?.username?.charAt(0) || user?.email?.charAt(0)}</AvatarFallback>
        </Avatar>
        <div className="space-y-2">
          <h1 className="text-3xl font-black italic tracking-tighter uppercase">
            {profile?.username || 'Shofer i Ri'}
          </h1>
          <div className="flex items-center justify-center gap-2">
            <Badge variant="outline" className="bg-accent/10 border-accent/20 text-accent font-bold px-4 py-1">
              {profile?.isPremium ? 'PREMIUM' : 'SHOFER KOSOVAR'}
            </Badge>
            <div className="flex items-center gap-1 text-[11px] font-bold text-muted-foreground uppercase bg-white/5 px-3 py-1 rounded-full">
              <MapPin className="w-3.5 h-3.5" />
              {profile?.city || 'Kosovë'}
            </div>
          </div>
        </div>

        <div className="flex gap-4 w-full mt-8">
          <div className="flex-1 glass rounded-3xl p-4 border-white/5">
            <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Ndjekës</p>
            <p className="text-xl font-black italic">0</p>
          </div>
          <div className="flex-1 glass rounded-3xl p-4 border-white/5">
            <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Gara</p>
            <p className="text-xl font-black italic">0</p>
          </div>
          <div className="flex-1 glass rounded-3xl p-4 border-white/5">
            <p className="text-[10px] font-black text-muted-foreground uppercase tracking-widest">Rangu</p>
            <p className="text-xl font-black italic text-accent">--</p>
          </div>
        </div>
      </div>

      <div className="px-6 mt-6 space-y-4">
        <div className="flex items-center justify-between">
          <h2 className="text-sm font-black uppercase tracking-widest text-muted-foreground">DETAJET E MJETIT</h2>
          <Button variant="ghost" size="sm" onClick={() => setIsEditDialogOpen(true)} className="text-accent hover:bg-accent/10 flex items-center gap-1 font-bold">
            <Edit3 className="w-4 h-4" />
            Ndrysho
          </Button>
        </div>

        <Card className="glass border-accent/20 p-6 rounded-[2rem] space-y-6">
          <div className="flex flex-col gap-1">
            <h3 className="text-2xl font-black italic text-white uppercase tracking-tighter">
              {profile?.carBrand || 'Pa specifikuar'} {profile?.carModel || ''}
            </h3>
            <p className="text-xs font-bold text-muted-foreground uppercase tracking-widest">
              {profile?.horsepower || 0} HP • KONFIGURIMI AKTUAL
            </p>
          </div>
          
          <div className="grid grid-cols-3 gap-4 pt-4 border-t border-white/5">
            <div className="text-center">
              <p className="text-[9px] font-black text-muted-foreground uppercase tracking-widest">0-100</p>
              <p className="text-lg font-black italic text-accent">--</p>
            </div>
            <div className="text-center border-x border-white/10">
              <p className="text-[9px] font-black text-muted-foreground uppercase tracking-widest">100-200</p>
              <p className="text-lg font-black italic text-accent">--</p>
            </div>
            <div className="text-center">
              <p className="text-[9px] font-black text-muted-foreground uppercase tracking-widest">TOP SPEED</p>
              <p className="text-lg font-black italic text-accent">--</p>
            </div>
          </div>
        </Card>

        <div className="glass rounded-3xl p-5 border-white/5 space-y-4">
          <h4 className="text-[10px] font-black text-accent uppercase tracking-widest flex items-center gap-2">
            <Zap className="w-3.5 h-3.5" />
            MODIFIKIMET E LISTUARA
          </h4>
          <div className="flex flex-wrap gap-2">
            {profile?.modifications ? (
              profile.modifications.split(',').map((mod: string, i: number) => (
                <Badge key={i} variant="outline" className="bg-white/5 border-white/10 text-xs py-1.5 px-3 rounded-xl">
                  {mod.trim()}
                </Badge>
              ))
            ) : (
              <p className="text-xs text-muted-foreground italic">Nuk ka modifikime të listuara</p>
            )}
          </div>
        </div>
      </div>

      <BottomNav />
    </div>
  );
}
